var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스, 내 말 들리나.","JPN":"アレックス、私の声が聞こえるか。","ENG":"Can you hear me, Alex?","TWN":"雅蕾克絲，能聽見我說話嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"메이즈 전대. 전 대원은 호출에 응답 바란다.","JPN":"メイズ戦隊の全隊員に告ぐ。私の呼びかけに応答願う。","ENG":"Maze Division. Come in, Maze Division.","TWN":"梅茲戰隊，全體隊員請回答我。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전원, 그동안 못난 전대장 밑에서 수고 많았다.","JPN":"皆、私が至らぬ戦隊長だったばかりに、\\nこれまでさんざん苦労をかけたな。","ENG":"I want to commend all of you for your dedicated service... You've suffered enough under an incompetent Commander.","TWN":"各位，在我這個沒出息的隊長手下做事，一定吃了不少苦吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그대들과 함께 싸운 지난날에 감사한다.","JPN":"君たちがともに戦ってくれた日々に、大いなる感謝を。","ENG":"I am most grateful for the opportunity to have fought by your side.","TWN":"感謝大家和我並肩作戰的時光。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그러니...... 이제는 편히 쉬도록.","JPN":"これからは……安らかに眠りたまえ。","ENG":"So... You may all rest in peace now.","TWN":"所以……好好休息吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흥미롭군.","JPN":"なかなか興味深いな。","ENG":"Interesting.","TWN":"有意思。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식 증후군이 막바지 단계에 접어들었는데 아무런 발작도 일으키지 않고 조용히 최후를 맞이하다니.","JPN":"侵食症候群が最終段階に差しかかってるというのに\\n何の発作も起こさず、こうも静かに最期を迎えるとは。","ENG":"Their Corruption syndrome has reached the final stage, but they're all slipping away so quietly, without so much as a seizure.","TWN":"侵蝕症候群都到了最終階段，卻沒有任何發作，平靜地迎接死亡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"숨이 멎기까지...... 앞으로 30분 정도인가.","JPN":"息絶えるまで……およそ30分といったところか。","ENG":"Looks like they've got... about 30 minutes until they stop breathing.","TWN":"離呼吸停止……還剩30分鐘左右吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......사장님.","JPN":"……社長。","ENG":"Boss.","TWN":"……老闆。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신에겐 익숙한 풍경이겠지만, 그래도 지금 꺼낼 말 같지는 않군요.","JPN":"あなたには見慣れた光景かもしれません。\\nですがそれでも、今はそんな言い方をしてほしくありません。","ENG":"I'm sure you're used to seeing this sort of stuff, but perhaps now's not the best time to be talking like that.","TWN":"這種場面您可能已經見慣了，但這種話還是不該在這時候說。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그만큼 오래 살았으면 눈치도 좀 있으셔야죠.","JPN":"長生きしてらっしゃるなら、場の空気くらいは読めるように\\nなっていただきたいものです。","ENG":"Come on, you're old enough to know better.","TWN":"您都活那麼久了，請您有點自覺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런가? 나는 그저 저 친구들을 살릴 수 있을 방법이 떠올랐을 뿐인데.","JPN":"おっと、そんなに​冷たく聞こえたか？　私はただ、あの戦隊員たちを\\n救う方法を思いついたので言ったのだがな。","ENG":"Oh, was I being inappropriate? I just realized how I could save them, that's all.","TWN":"是嗎？我只是想到了救回這些朋友們的方法而已啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"또 무슨 변명을...... 네?","JPN":"また何か言い訳を……はい？","ENG":"There you go again with your ridiculous excuse—huh?","TWN":"您又在說什麼鬼……什麼？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방금 뭐라고 했습니까? 대원들을 살릴 수 있다고요?","JPN":"今、何とおっしゃいました？　隊員たちを救う手立てがあるのですか？","ENG":"What did you just say? You can save them?","TWN":"您剛才說什麼？救活隊員們的方法？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"매우 위험한 방법이지만, 자네만 동의한다면 시도해 볼 수는 있지.","JPN":"非常に危険な方法だが、君さえ同意するなら試してみることはできる。","ENG":"It's very dangerous, but we could give it a try, with your consent.","TWN":"雖然這方法很危險，但只要妳同意的話，還是可以試一試。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐든 좋습니다!","JPN":"何だって構いません！","ENG":"Anything!","TWN":"不論什麼我都願意！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들을 살릴 수 있다면 뭐든 하겠습니다! 말씀해 주십시오!","JPN":"隊員たちを助けられるなら、私は何だってします！\\n何でもお申し付けください！","ENG":"I'd do anything if we can save them! Just tell me!","TWN":"只要能救回隊員們，我什麼都願意做！請快說吧！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};